const LAYER_KEYS = [
  'water',
  'buffer',
  'roads',
  'green',
  'social',
  'utility',
  'boundary',
  'splay'
];

const PADDING = 34;
const SCALE = 2.58;
const HALO_EXT = 260;

function getAllPoints() {
  const plotPoints = Array.isArray(D.plots) ? D.plots.flatMap(p => p.p || []) : [];
  const layerPoints = LAYER_KEYS.flatMap(key =>
    Array.isArray(D[key]) ? D[key].flatMap(poly => poly || []) : []
  );
  return [...plotPoints, ...layerPoints];
}

const ALL_POINTS = getAllPoints();

const BOUNDS = ALL_POINTS.reduce(
  (acc, [x, y]) => ({
    minX: Math.min(acc.minX, x),
    minY: Math.min(acc.minY, y),
    maxX: Math.max(acc.maxX, x),
    maxY: Math.max(acc.maxY, y)
  }),
  { minX: Infinity, minY: Infinity, maxX: -Infinity, maxY: -Infinity }
);

const MAP_W = (BOUNDS.maxX - BOUNDS.minX) * SCALE + PADDING * 2;
const MAP_H = (BOUNDS.maxY - BOUNDS.minY) * SCALE + PADDING * 2;
const VIEW_W = MAP_W + HALO_EXT;
const VIEW_H = MAP_H;

function toSvgPoint([x, y]) {
  return [
    (x - BOUNDS.minX) * SCALE + PADDING,
    (y - BOUNDS.minY) * SCALE + PADDING
  ];
}

function ptsToPath(pts) {
  return pts.map(pt => toSvgPoint(pt).join(',')).join(' ');
}

function pathFromPoints(pts) {
  return pts.map((pt, i) => {
    const [x, y] = toSvgPoint(pt);
    return `${i === 0 ? 'M' : 'L'} ${x} ${y}`;
  }).join(' ');
}

function centroid(pts) {
  if (!Array.isArray(pts) || pts.length === 0) return [0, 0];

  let area = 0;
  let cx = 0;
  let cy = 0;

  for (let i = 0; i < pts.length; i++) {
    const [x1, y1] = pts[i];
    const [x2, y2] = pts[(i + 1) % pts.length];
    const cross = x1 * y2 - x2 * y1;
    area += cross;
    cx += (x1 + x2) * cross;
    cy += (y1 + y2) * cross;
  }

  area *= 0.5;

  if (Math.abs(area) < 0.00001) {
    let sx = 0;
    let sy = 0;
    pts.forEach(([x, y]) => {
      sx += x;
      sy += y;
    });
    return [sx / pts.length, sy / pts.length];
  }

  return [cx / (6 * area), cy / (6 * area)];
}

function getPlot(n) {
  return D.plots.find(p => p && p.n === n);
}

