const GeoHalos = React.memo(function GeoHalos({ theme }) {
  const cx = MAP_W * 0.75;
  const cy = MAP_H * 0.42;
  const baseR = MAP_H * 0.52;
  const a0 = -Math.PI * 0.38;
  const a1 = Math.PI * 0.38;

  return (
    <g style={{ pointerEvents: 'none' }}>
      <defs>
        {HALOS.map((h, i) => {
          const r = baseR * h.r;
          const x1 = cx + r * Math.cos(a0);
          const y1 = cy + r * Math.sin(a0);
          const x2 = cx + r * Math.cos(a1);
          const y2 = cy + r * Math.sin(a1);

          return (
            <path
              key={`hd-${i}`}
              id={`halo-${i}`}
              d={`M ${x1},${y1} A ${r},${r} 0 0,1 ${x2},${y2}`}
              fill="none"
            />
          );
        })}
      </defs>

      {HALOS.map((h, i) => (
        <g key={`hg-${i}`}>
          <use
            href={`#halo-${i}`}
            fill="none"
            stroke={theme.accent}
            strokeOpacity="0.07"
            strokeWidth="0.55"
            strokeDasharray="4,6"
          />

          <text
            fill={theme.accent}
            fillOpacity="0.3"
            fontSize="5.5"
            letterSpacing="2"
            style={{
              fontFamily: "'JetBrains Mono', monospace",
              fontWeight: 500
            }}
          >
            <textPath href={`#halo-${i}`} startOffset="50%" textAnchor="middle">
              {h.label}
            </textPath>
          </text>
        </g>
      ))}
    </g>
  );
});

